mapper.select:
select * from refund_requests

    applicant_id = #{applicantId}
    and status = #{status}

order by create_time desc

select r.* from refund_requests r
inner join product_orders p on r.order_id = p.order_id and r.order_type = 1
where p.seller_id = #{sellerId}
and r.status = #{status}
order by r.create_time desc

select r.* from refund_requests r
inner join errand_orders e on r.order_id = e.order_id and r.order_type = 2
where e.runner_id = #{runnerId}
and r.status = #{status}
order by r.create_time desc

select * from refund_requests

    and order_type = #{orderType}
    and status = #{status}

order by create_time desc
